func (r *Runner) Apply(m Migration) error {
    sum := sha256.Sum256([]byte(m.SQL))
    existing, err := r.getChecksum(m.ID)
    if err == nil && existing != fmt.Sprintf("%x", sum) {
        return fmt.Errorf("migration %s checksum mismatch: possible tampering", m.ID)
    }
    _, err = r.db.Exec(m.SQL)
    if err != nil {
        return err
    }
    return r.storeChecksum(m.ID, fmt.Sprintf("%x", sum))
}

